 1	import React, { FC } from 'react';
 2	
 3	import {
 4	  V1VirtualMachine,
 5	  V1VirtualMachineInstance,
 6	  V1Volume,
 7	} from '@kubevirt-ui/kubevirt-api/kubevirt';
 8	import ConfirmActionMessage from '@kubevirt-utils/components/ConfirmActionMessage/ConfirmActionMessage';
 9	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
11	import { getVMIVolumes } from '@kubevirt-utils/resources/vmi';
12	import { Stack, StackItem } from '@patternfly/react-core';
13	
14	import { updateDisks } from '../../../details/utils/utils';
15	
16	import { persistVolume } from './utils';
17	
18	type MakePersistentModalProps = {
19	  isOpen: boolean;
20	  onClose: () => void;
21	  vm: V1VirtualMachine;
22	  vmi: V1VirtualMachineInstance;
23	  volume: V1Volume;
24	};
25	
26	const MakePersistentModal: FC<MakePersistentModalProps> = ({
27	  isOpen,
28	  onClose,
29	  vm,
30	  vmi,
31	  volume,
32	}) => {
33	  const { t } = useKubevirtTranslation();
34	
35	  const makePersistent = async () => {
36	    const volumeToPersist = getVMIVolumes(vmi).find((vmiVolume) => vmiVolume.name === volume?.name);
37	
38	    const vmPersistent = await persistVolume(vm, vmi, volumeToPersist);
39	
40	    return updateDisks(vmPersistent);
41	  };
42	
43	  return (
44	    <TabModal<V1VirtualMachine>
45	      headerText={t('Make persistent?')}
46	      isOpen={isOpen}
47	      onClose={onClose}
48	      onSubmit={makePersistent}
49	    >
50	      <Stack hasGutter>
51	        <StackItem>
52	          <ConfirmActionMessage
53	            obj={{
54	              metadata: { name: volume?.name },
55	            }}
56	            action="make persistent"
57	          />
58	        </StackItem>
59	      </Stack>
60	    </TabModal>
61	  );
62	};
63	
64	export default MakePersistentModal;

